SELECT count(*) FROM movie_info, info_type, title, movie_companies, cast_info, company_name, name, company_type, char_name WHERE movie_info.info_type_id = info_type.id AND movie_info.movie_id = title.id AND movie_companies.movie_id = title.id AND cast_info.movie_id = title.id AND movie_companies.company_id = company_name.id AND cast_info.person_id = name.id AND movie_companies.company_type_id = company_type.id AND cast_info.person_role_id = char_name.id;